<!DOCTYPE html>
<html>
<head>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: sans-serif; overflow: hidden; }
  #desktop { position: fixed; top: 0; left: 0; width: 100vw; height: 100vh; background: #1e1e1e; }
  #taskbar { position: fixed; bottom: 0; width: 100%; height: 40px; background: #333; display: flex; align-items: center; padding: 5px; gap: 10px; }
  .launcher { padding: 5px 15px; background: #555; color: white; border: none; cursor: pointer; border-radius: 3px; }
  .launcher:hover { background: #777; }
  .window { position: absolute; width: 400px; height: 300px; background: #2e3436; border: 1px solid #3c3c3c; display: none; z-index: 100; }
  .win-title { position: absolute; top: 0; left: 0; right: 30px; height: 25px; background: #333; color: white; display: flex; align-items: center; padding: 0 10px; }
  .win-close { position: absolute; top: 3px; right: 5px; width: 18px; height: 18px; background: #cc0000; color: white; border: none; border-radius: 3px; cursor: pointer; font-size: 12px; line-height: 18px; text-align: center; }
  #files-path, #files-up { position: absolute; top: 5px; font-size: 12px; color: #aaa; }
  #files-path { left: 5px; }
  #files-up { right: 5px; background: #555; color: white; border: none; padding: 2px 6px; cursor: pointer; border-radius: 2px; }
  #files-listing { position: absolute; top: 30px; left: 5px; right: 5px; bottom: 30px; overflow-y: auto; }
  .fs-item { padding: 5px; cursor: pointer; }
  .fs-item:hover { background: #444; }
  #notepad-tabs { position: absolute; top: 5px; left: 5px; right: 5px; height: 25px; display: flex; align-items: center; gap: 2px; border-bottom: 1px solid #555; }
  .tab { padding: 3px 8px; background: #555; color: white; cursor: pointer; border-radius: 3px 3px 0 0; }
  .tab.active { background: #777; }
  #new-tab { margin-left: auto; padding: 3px 8px; background: #555; color: white; border: none; cursor: pointer; border-radius: 3px; }
  #editor { position: absolute; top: 30px; left: 5px; right: 5px; bottom: 5px; background: white; color: black; border: none; font-family: monospace; padding: 10px; resize: none; }
</style>
</head>
<body>
<div id="desktop">
  <div id="taskbar">
    <button id="open-files" class="launcher">Files</button>
    <button id="open-notepad" class="launcher">Notepad</button>
  </div>

  <div id="files-window" class="window">
    <div class="win-title">Files</div>
    <button class="win-close" onclick="document.getElementById('files-window').style.display='none'">×</button>
    <div id="files-path">/</div>
    <button id="files-up" onclick="navigateUp()">↑</button>
    <div id="files-listing"></div>
  </div>

  <div id="notepad-window" class="window">
    <div class="win-title">Notepad</div>
    <button class="win-close" onclick="document.getElementById('notepad-window').style.display='none'">×</button>
    <div id="notepad-tabs"></div>
    <button id="new-tab" style="position:absolute; top:5px; right:5px;">+</button>
    <textarea id="editor"></textarea>
  </div>
</div>

<script>
// File System Structure
const fileSystem = {
  '/': {
    type: 'dir',
    contents: {
      bin: { type: 'dir', contents: {} },
      etc: { type: 'dir', contents: {} },
      home: { 
        type: 'dir', 
        contents: {
          user: { 
            type: 'dir', 
            contents: {
              Documents: { type: 'file' },
              Downloads: { type: 'file' },
              Pictures: { type: 'file' }
            }
          }
        }
      },
      usr: { type: 'dir', contents: {} },
      var: { type: 'dir', contents: {} }
    }
  }
};

let currentPath = '/';

function getContents(path) {
  const parts = path.split('/').filter(p => p);
  let current = fileSystem['/'].contents;
  for (const part of parts) {
    current = current[part].contents;
  }
  return current;
}

function renderFiles() {
  const contents = getContents(currentPath);
  const listing = document.getElementById('files-listing');
  listing.innerHTML = '';

  for (const name in contents) {
    const item = contents[name];
    const el = document.createElement('div');
    el.className = 'fs-item';
    el.textContent = name;

    if (item.type === 'dir') {
      el.addEventListener('dblclick', () => {
        currentPath = currentPath === '/' ? `/${name}` : `${currentPath}/${name}`;
        document.getElementById('files-path').textContent = currentPath;
        renderFiles();
      });
    }

    listing.appendChild(el);
  }

  document.getElementById('files-path').textContent = currentPath;
}

function navigateUp() {
  if (currentPath === '/') return;
  const parts = currentPath.split('/').filter(p => p);
  parts.pop();
  currentPath = '/' + parts.join('/');
  document.getElementById('files-path').textContent = currentPath;
  renderFiles();
}

// Notepad State
let tabs = JSON.parse(localStorage.getItem('notepadTabs') || '[]');
let activeTabIndex = parseInt(localStorage.getItem('notepadActiveTab') || '0');

function saveNotepadState() {
  localStorage.setItem('notepadTabs', JSON.stringify(tabs));
  localStorage.setItem('notepadActiveTab', activeTabIndex);
}

function renderTabs() {
  const container = document.getElementById('notepad-tabs');
  container.innerHTML = '';

  tabs.forEach((tab, index) => {
    const tabEl = document.createElement('div');
    tabEl.className = 'tab';
    tabEl.textContent = `Tab ${index + 1}`;
    if (index === activeTabIndex) tabEl.classList.add('active');
    tabEl.addEventListener('click', () => {
      activeTabIndex = index;
      saveNotepadState();
      updateEditor();
      renderTabs();
    });
    container.appendChild(tabEl);
  });

  const newTabBtn = document.getElementById('new-tab');
  newTabBtn.onclick = () => {
    tabs.push({ content: '' });
    activeTabIndex = tabs.length - 1;
    saveNotepadState();
    renderTabs();
    updateEditor();
  };
}

function updateEditor() {
  document.getElementById('editor').value = tabs[activeTabIndex]?.content || '';
}

document.getElementById('editor').addEventListener('input', (e) => {
  tabs[activeTabIndex].content = e.target.value;
  saveNotepadState();
});

// Window Management
document.getElementById('open-files').addEventListener('click', () => {
  const win = document.getElementById('files-window');
  win.style.display = 'block';
  currentPath = '/';
  renderFiles();
});

document.getElementById('open-notepad').addEventListener('click', () => {
  const win = document.getElementById('notepad-window');
  win.style.display = 'block';
  if (tabs.length === 0) {
    tabs = JSON.parse(localStorage.getItem('notepadTabs') || '[]');
    activeTabIndex = parseInt(localStorage.getItem('notepadActiveTab') || '0');
  }
  renderTabs();
  updateEditor();
});

// Initial render
renderFiles();
renderTabs();
</script>
</body>
</html>
